        :unit_metros                 => "Metros",
        :unit_centimetros            => "Centimetros",
        :unit_milimetros             => "Milimetros",
        :unit_polegadas              => "Polegadas",
        :unit_jardas                 => "Jardas",
        :unit_pes                    => "Pes"
      },
      'en-US' => {
        :titulo                      => "Sections Management",
        :selecionar_pavimento        => "-- Select a floor --",
        :editar_pavimento            => "Edit Floor:",
        :selecionar_unidade          => "Measurement Unit:",
        :nome_pavimento              => "Floor Name:",
        :placeholder_nome            => "Enter floor name",
        :nivel_pavimento             => "Floor Elevation:",
        :altura_pavimento            => "Floor Height:",
        :planta_baixa_altura         => "Floor Plan (height):",
        :botao_salvar                => "Save changes",
        :botao_criar                 => "Create Floor",
        :titulo_niveis               => "Floors:",
        :carregar_dados              => "Load data",
        :botao_excluir               => "Delete",
        :botao_salvar_dados          => "Save",
        :secoes_forro                => "Ceiling Sections",
        :secoes_planta               => "Plan Sections",
        :secoes_corte                => "Sections",
        :corte_extra_x               => "Extra Cut X",
        :corte_extra_y               => "Extra Cut Y",
        :idioma                      => "Language",
        :tema_claro                  => "Light Theme",
        :tema_escuro                 => "Dark Theme",
        :sem_geometria               => "No geometry found to place cuts!",
        :confirmar_exclusao_titulo   => "Do you want to delete selected floors?",
        :confirmar_exclusao_mensagem => "This action is irreversible and will delete all configuration for selected floors.",
        :botao_cancelar              => "Cancel",
        :botao_confirmar             => "Confirm",
        :titulo_alerta               => "Warning",
        :numero_invalido             => "Please enter valid numeric values",
        :nenhum_selecionado          => "Select at least one floor",
        :dados_salvos                => "Data successfully saved at:",
        :erro                        => "Error",
        :secao_frente                => "Front",
        :secao_tras                  => "Back",
        :secao_direita               => "Right",
        :secao_esquerda              => "Left",
