        :nome_duplicado              => "A floor with this name already exists, please choose a unique name",
        :nivel_duplicado             => "Floor elevation already exists, check the table to avoid duplicate floors",
        :criar_secoes_primeiro       => "Create vertical sections first or check if there is visible geometry!",
        :arquivo_invalido            => "Invalid file",
