        :unit_pes                    => "Feet"
      },
      'es' => {
        :titulo                      => "Gestor de Pisos",
        :selecionar_pavimento        => "-- Seleccione un piso --",
        :editar_pavimento            => "Editar Piso:",
        :selecionar_unidade          => "Unidad de Medida:",
        :nome_pavimento              => "Nombre del Piso:",
        :placeholder_nome            => "Ingrese nombre del piso",
        :nivel_pavimento             => "Elevacion del Piso:",
        :altura_pavimento            => "Altura del Piso:",
        :planta_baixa_altura         => "Plano de Planta (altura):",
        :botao_salvar                => "Guardar cambios",
        :botao_criar                 => "Crear Piso",
        :titulo_niveis               => "Pisos en el Proyecto:",
        :carregar_dados              => "Cargar datos",
        :botao_excluir               => "Eliminar",
        :botao_salvar_dados          => "Guardar",
        :secoes_forro                => "Secciones de Techo",
        :secoes_planta               => "Secciones de Planta",
        :secoes_corte                => "Secciones",
        :corte_extra_x               => "Corte Extra X",
        :corte_extra_y               => "Corte Extra Y",
        :idioma                      => "Idioma",
        :tema_claro                  => "Tema Claro",
        :tema_escuro                 => "Tema Oscuro",
        :sem_geometria               => "No se encontro geometria para colocar cortes!",
        :confirmar_exclusao_titulo   => "Desea eliminar los pisos seleccionados?",
        :confirmar_exclusao_mensagem => "Esta accion es irreversible y eliminara toda la configuracion de los pisos seleccionados.",
        :botao_cancelar              => "Cancelar",
        :botao_confirmar             => "Confirmar",
        :titulo_alerta               => "Atencion",
        :numero_invalido             => "Por favor ingrese valores numericos validos",
        :nenhum_selecionado          => "Seleccione al menos un piso",
        :dados_salvos                => "Datos guardados exitosamente en:",
        :erro                        => "Error",
        :secao_frente                => "Frente",
        :secao_tras                  => "Atras",
        :secao_direita               => "Derecha",
        :secao_esquerda              => "Izquierda",
        :secao                       => "Seccion",
        :nome_duplicado              => "Ya existe un piso con este nombre, elija un nombre unico para el nuevo piso",
        :nivel_duplicado             => "La elevacion del piso ya existe, verifique en la tabla para no crear pisos duplicados",
        :criar_secoes_primeiro       => "Cree las secciones verticales primero o verifique si hay geometria visible!",
        :arquivo_invalido            => "Archivo invalido",
        :cabecalho_nome              => "Piso",
        :cabecalho_nivel             => "Elevacion",
        :cabecalho_altura            => "Altura",
        :cabecalho_planta            => "Plano de Planta",
        :cabecalho_planta_z          => "PL(z)",
        :unit_metros                 => "Metros",
        :unit_centimetros            => "Centimetros",
        :unit_milimetros             => "Milimetros",
        :unit_polegadas              => "Pulgadas",
        :unit_jardas                 => "Yardas",
        :unit_pes                    => "Pies"
      }
    }

    LANG_MAP = { 'pt' => 'pt-BR', 'en' => 'en-US', 'es' => 'es' }
    LANG_SHORT = { 'pt-BR' => 'pt', 'en-US' => 'en', 'es' => 'es' }

    UNIT_KEYS = [
      ['metros',      :unit_metros],
      ['centimetros', :unit_centimetros],
      ['milimetros',  :unit_milimetros],
      ['polegadas',   :unit_polegadas],
      ['jardas',      :unit_jardas],
      ['pes',         :unit_pes]
    ]

    # Inicializa variaveis de classe
    @levels = []
    @dialog = nil
    @current_unit = 'metros'
    @current_theme = Sketchup.read_default("level_manager", "theme", "day")
    @levels_mutex = Mutex.new

    # Detecta idioma inicial via Sketchup.get_locale ou preferencia salva
    saved_lang = Sketchup.read_default("level_manager", "language", nil)
    if saved_lang && IDIOMAS.key?(saved_lang)
      @current_language = saved_lang
    elsif saved_lang && LANG_MAP.key?(saved_lang)
      @current_language = LANG_MAP[saved_lang]
    else
      locale = Sketchup.get_locale
      @current_language = IDIOMAS.key?(locale) ? locale : 'en-US'
    end

    def self.obter_texto(chave)
      lang = @current_language || begin
        locale = Sketchup.get_locale
        IDIOMAS.key?(locale) ? locale : 'en-US'
      end
      IDIOMAS[lang][chave] || IDIOMAS['en-US'][chave] || chave.to_s
    end

    # Metodo principal para criar a interface
    def self.criar_interface_niveis
      begin
        # Fecha o dialogo existente se estiver aberto
        @dialog.close if @dialog && @dialog.visible?

        options = {
          :dialog_title => obter_texto(:titulo),
          :preferences_key => 'com.example.levelmanager',
          :width => 650,
          :height => 580,
          :resizable => true,
          :style => UI::HtmlDialog::STYLE_DIALOG,
          :min_width => 650,
          :min_height => 580
        }

        @dialog = UI::HtmlDialog.new(options)

        unit_options = UNIT_KEYS.map { |val, key| "<option value='#{val}'>#{obter_texto(key)}</option>" }.join
        short_lang = LANG_SHORT[@current_language] || 'en'

        html = <<-HTML
          <!DOCTYPE html>
          <html>
          <head>
            <meta charset="UTF-8">
            <style>
              /* ====== ESTILOS GERAIS ====== */
              body {
                font-family: Arial, sans-serif;
                padding: 10px;
                margin: 0;
                height: 100%;
                box-sizing: border-box;
                background-color: #ffffff;
                color: #000000;
              }

              /* Tema noturno */
              body.night {
                background-color: #000000;
                color: #ffffff;
              }

              /* ====== LAYOUT PRINCIPAL ====== */
              #main-container {
                display: flex;
                flex-direction: column;
                height: 100%;
              }

              /* Container da tabela */
              #table-container {
                flex-grow: 1;
                overflow-y: auto;
                margin-bottom: 10px;
              }

              /* ====== CABECALHOS E TITULOS ====== */
              h3 {
                margin-top: 0;
              }

              h4 {
                margin-bottom: 5px;
                display: flex;
                align-items: center;
              }

              /* ====== FORMULARIOS E INPUTS ====== */
              /* Grupos de inputs */
              .input-group {
                margin-bottom: 12px;
              }

              .name-input-group {
                margin-top: 8px;
                margin-bottom: 15px;
              }

              /* Linhas de inputs */
              .input-row {
                display: flex;
                justify-content: space-between;
                margin-bottom: 12px;
              }

              .selector-row {
                display: flex;
                justify-content: space-between;
                margin-bottom: 15px;
              }

              /* Seletor de idioma */
              .language-selector {
                position: absolute;
                top: 10px;
                right: 60px;
                display: flex;
                align-items: center;
                gap: 5px;
                font-size: 9pt;
              }

              .language-selector select {
                padding: 2px;
                font-size: 9pt;
              }

              /* Campos individuais */
              .input-field {
                width: 30%;
              }

              .unit-selector,
              .level-selector {
                width: 48%;
              }

              /* Labels */
              .input-label {
                font-size: 10pt;
                margin-bottom: 2px;
              }

              .input-field label {
                font-size: 10pt;
                display: block;
                margin-bottom: 2px;
              }

              /* Inputs e selects */
              .input-field input,
              select,
              #level_name {
                width: 100%;
                padding: 4px;
                font-size: 11pt;
                box-sizing: border-box;
                background-color: #ffffff;
                color: #000000;
                border: 1px solid #ddd;
              }

              /* Input de nome do nivel */
              #level_name {
                width: 100%;
              }

              /* ====== TABELA DE NIVEIS ====== */
              table {
                width: 100%;
                border-collapse: collapse;
                margin-top: 8px;
                font-size: 11pt;
                table-layout: fixed;
              }

              th, td {
                border: 1px solid #ddd;
                padding: 6px;
                text-align: left;
                overflow: hidden;
              }

              th {
                background-color: #f2f2f2;
                font-size: 10pt;
                white-space: nowrap;
              }

              /* Celulas editaveis */
              .editable-cell {
                cursor: pointer;
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .editable-cell:hover {
                background-color: #f5f5f5;
              }

              /* Checkbox na tabela */
              .checkbox-column {
                width: 30px;
                text-align: center;
              }

              /* Input dentro da tabela */
              .table-input {
                width: 100%;
                border: none;
                padding: 0;
                margin: 0;
                font-size: 11pt;
                background: transparent;
                color: inherit;
              }

              /* ====== BOTOES ====== */
              /* Containers de botoes */
              .button-container {
                display: flex;
                justify-content: space-between;
                margin-top: 15px;
                margin-bottom: 10px;
              }

              .button-row {
                display: flex;
                justify-content: space-between;
                margin-top: 10px;
              }

              .delete-save-container {
                display: flex;
                gap: 5px;
              }

              /* Estilo base para todos os botoes */
              button {
                padding: 5px 12px;
                margin: 3px;
                font-size: 11pt;
                cursor: pointer;
                border: none;
                border-radius: 8px;
              }

              /* Cores especificas para botoes */
              .delete-btn {
                background-color: #f44336;
                color: white;
              }

              .create-btn {
                background-color: #2196F3;
                color: white;
              }

              .save-btn {
                background-color: #4CAF50;
                color: white;
              }

              .section-btn {
                background-color: #2196F3;
                color: white;
              }

              .cut-btn {
                background-color: #42A5F5;
                color: white;
              }

              .load-btn {
                background-color: #9E9E9E;
                color: white;
                padding: 3px 8px;
                font-size: 10pt;
                height: 24px;
                margin-left: 5px;
              }

              /* ====== SECOES ESPECIFICAS ====== */
              /* Seletor de tema */
              .theme-switcher {
                position: absolute;
                top: 10px;
                right: 10px;
                display: flex;
                gap: 0;
              }

              .theme-btn {
                width: 24px;
                height: 24px;
                padding: 0;
                margin: 0;
                display: flex;
                align-items: center;
                justify-content: center;
                border: 1px solid #ccc;
                background-color: #f0f0f0;
                border-radius: 0;
                color: #000;
              }

              .theme-btn:first-child {
                border-top-left-radius: 3px;
                border-bottom-left-radius: 3px;
              }

              .theme-btn:last-child {
                border-top-right-radius: 3px;
                border-bottom-right-radius: 3px;
              }

              .theme-btn.active {
                background-color: #ddd;
                border: 1px solid #999;
                box-shadow: inset 0 2px 3px rgba(0,0,0,0.2);
              }

              /* ====== DIALOGOS PERSONALIZADOS ====== */
              .custom-dialog {
                position: fixed;
                top: 50%;
                left: 50%;
                transform: translate(-50%, -50%);
                background-color: white;
                padding: 20px;
                border-radius: 5px;
                box-shadow: 0 4px 8px rgba(0,0,0,0.2);
                z-index: 1000;
                width: 400px;
                max-width: 90%;
              }

              .custom-dialog-title {
                font-weight: bold;
                margin-bottom: 15px;
                font-size: 14pt;
              }

              .custom-dialog-message {
                margin-bottom: 20px;
              }

              .custom-dialog-buttons {
                display: flex;
                justify-content: flex-end;
                gap: 10px;
              }

              .custom-dialog-button {
                padding: 8px 16px;
                border: none;
                border-radius: 4px;
                cursor: pointer;
                font-size: 11pt;
              }

              .custom-dialog-confirm {
                background-color: #f44336;
                color: white;
              }

              .custom-dialog-cancel {
                background-color: #e0e0e0;
              }

              /* ====== TEMA NOTURNO ====== */
              body.night .input-field input,
              body.night select,
              body.night #level_name,
              body.night .table-input {
                background-color: #333333;
                color: #ffffff;
                border-color: #555;
              }

              body.night th,
              body.night td {
                border-color: #555;
              }

              body.night th {
                background-color: #333;
              }

              body.night .editable-cell:hover {
                background-color: #333;
              }

              body.night .theme-btn {
                background-color: #333;
                border-color: #555;
                color: #fff;
              }

              body.night .theme-btn.active {
                background-color: #555;
                border-color: #777;
              }

              body.night .custom-dialog {
                background-color: #222;
                color: white;
              }

              body.night .custom-dialog-cancel {
                background-color: #444;
                color: white;
              }
            </style>
          </head>
          <body class="#{@current_theme}">
            <div class="language-selector">
              <label>#{obter_texto(:idioma)}:</label>
              <select id="language_selector" onchange="changeLanguage()">
                <option value="pt" #{@current_language == 'pt-BR' ? 'selected' : ''}>Portugu&#234;s</option>
                <option value="en" #{@current_language == 'en-US' ? 'selected' : ''}>English</option>
                <option value="es" #{@current_language == 'es' ? 'selected' : ''}>Espa&#241;ol</option>
              </select>
            </div>

            <div class="theme-switcher">
              <button id="day-theme" class="theme-btn #{@current_theme == 'day' ? 'active' : ''}" onclick="setTheme('day')" title="#{obter_texto(:tema_claro)}">&#128262;</button>
              <button id="night-theme" class="theme-btn #{@current_theme == 'night' ? 'active' : ''}" onclick="setTheme('night')" title="#{obter_texto(:tema_escuro)}">&#127769;</button>
            </div>

            <div id='main-container'>
              <h3>#{obter_texto(:titulo)}</h3>

              <div class='selector-row'>
                <div class='level-selector'>
                  <label class='input-label'>#{obter_texto(:editar_pavimento)}</label>
                  <select id='level_selector' onchange='levelSelected()'>
                    <option value=''>#{obter_texto(:selecionar_pavimento)}</option>
                  </select>
                </div>
                <div class='unit-selector'>
                  <label class='input-label'>#{obter_texto(:selecionar_unidade)}</label>
                  <select id='unit_selector' onchange='unitChanged()'>
                    #{unit_options}
                  </select>
                </div>
              </div>

              <div class='name-input-group'>
                <label class='input-label'>#{obter_texto(:nome_pavimento)}</label>
                <input type='text' id='level_name' placeholder="#{obter_texto(:placeholder_nome)}" onkeypress="handleKeyPress(event)">
              </div>

              <div class='input-row'>
                <div class='input-field'>
                  <label class='input-label'>#{obter_texto(:nivel_pavimento)}</label>
                  <input type='text' id='base_level' value='0,00' onfocus="this.select();" onkeypress="handleKeyPress(event)">
                </div>
                <div class='input-field'>
                  <label class='input-label'>#{obter_texto(:altura_pavimento)}</label>
                  <input type='text' id='level_height' value='3,00' onfocus="this.select();" onkeypress="handleKeyPress(event)">
                </div>
                <div class='input-field'>
                  <label class='input-label'>#{obter_texto(:planta_baixa_altura)}</label>
                  <input type='text' id='plan_height' value='1,50' onfocus="this.select();" onkeypress="handleKeyPress(event)">
                </div>
              </div>

              <div class='button-row'>
                <button onclick='saveLevel()' class='save-btn'>#{obter_texto(:botao_salvar)}</button>
                <button onclick='addLevel()' class='create-btn'>#{obter_texto(:botao_criar)}</button>
              </div>

              <div id='table-container'>
                <h4>#{obter_texto(:titulo_niveis)}<button class='load-btn' onclick='loadData()'>#{obter_texto(:carregar_dados)}</button></h4>
                <table id='levels_table'>
                  <thead>
                    <tr>
                      <th class='checkbox-column'><input type='checkbox' id='select_all' onclick='toggleSelectAll()'></th>
                      <th width='25%'>#{obter_texto(:cabecalho_nome)}</th>
                      <th width='15%'>#{obter_texto(:cabecalho_nivel)}</th>
                      <th width='15%'>#{obter_texto(:cabecalho_altura)}</th>
                      <th width='15%'>#{obter_texto(:cabecalho_planta)}</th>
                      <th width='15%'>#{obter_texto(:cabecalho_planta_z)}</th>
                    </tr>
                  </thead>
                  <tbody id='levels_list'>
                  </tbody>
                </table>
              </div>

              <div class='button-container'>
                  <div class='delete-save-container'>
                      <button onclick='showDeleteConfirmation()' class='delete-btn'>#{obter_texto(:botao_excluir)}</button>
                      <button onclick='saveData()' class='save-btn'>#{obter_texto(:botao_salvar_dados)}</button>
                  </div>

