                sketchup.addLevel(name, baseZ.replace(',', '.'), height.replace(',', '.'), planHeight.replace(',', '.'));
              }

              function saveLevel() {
                const levelId = document.getElementById('level_selector').value;
                if (!levelId) {
                  showAlert('#{obter_texto(:titulo_alerta)}', '#{obter_texto(:selecionar_pavimento)}');
                  return;
                }

                const name = document.getElementById('level_name').value.trim();
                const baseZ = document.getElementById('base_level').value;
                const height = document.getElementById('level_height').value;
                const planHeight = document.getElementById('plan_height').value;

                if (!validateNumber(baseZ) || !validateNumber(height) || !validateNumber(planHeight)) {
                  showAlert('#{obter_texto(:titulo_alerta)}', '#{obter_texto(:numero_invalido)}');
