              function showAlert(title, message) {
                const dialog = document.createElement('div');
                dialog.className = 'custom-dialog';
                dialog.innerHTML = `
                  <div class="custom-dialog-title">${title}</div>
                  <div class="custom-dialog-message">${message}</div>
