                const dialog = document.createElement('div');
                dialog.className = 'custom-dialog';
                dialog.innerHTML = `
                  <div class="custom-dialog-title">#{obter_texto(:confirmar_exclusao_titulo)}</div>
                  <div class="custom-dialog-message">#{obter_texto(:confirmar_exclusao_mensagem)}</div>
                  <div class="custom-dialog-buttons">
                    <button class="custom-dialog-button custom-dialog-cancel" onclick="this.parentNode.parentNode.remove()">#{obter_texto(:botao_cancelar)}</button>
                    <button class="custom-dialog-button custom-dialog-confirm" onclick="confirmDelete()">#{obter_texto(:botao_confirmar)}</button>
                  </div>
                `;

                document.body.appendChild(dialog);

                window.confirmDelete = function() {
                  const levelsToDelete = Array.from(checkboxes).map(cb => cb.getAttribute('data-id'));
                  sketchup.deleteLevels(levelsToDelete);
                  dialog.remove();
