              function unitChanged() {
                const unitSelector = document.getElementById('unit_selector');
                sketchup.setCurrentUnit(unitSelector.value);
              }

              function updateUI() {
                sketchup.updateUI();
              }

              function editCell(cell, levelId, field, isText = false) {
                const currentValue = cell.textContent.replace('m', '').trim();
                const input = document.createElement('input');
                input.type = 'text';
                input.className = 'table-input';
                input.value = currentValue;

                input.onblur = function() {
                  if (input.value !== currentValue) {
                    if (!isText && !validateNumber(input.value)) {
                      showAlert('#{obter_texto(:titulo_alerta)}', '#{obter_texto(:numero_invalido)}');
                      return;
                    }
                    sketchup.editLevelField(levelId, field, isText ? input.value : input.value.replace(',', '.'));
                  }
                  cell.textContent = isText ? input.value : formatNumber(parseFloat(input.value.replace(',', '.'))) + 'm';
                };

                input.onkeypress = function(e) {
                  if (e.key === 'Enter') {
                    input.blur();
                  }
                };

                cell.innerHTML = '';
                cell.appendChild(input);
                input.focus();

                setTimeout(() => {
                  input.selectionStart = input.selectionEnd = input.value.length;
                }, 0);
              }

              function loadData() {
                sketchup.loadData();
              }

              function saveData() {
                sketchup.saveData();
              }

              function createCeilingSections() {
                const checkboxes = document.querySelectorAll('#levels_list input[type="checkbox"]:checked');
