                const levelsToCreate = Array.from(checkboxes).map(cb => {
                  return {
                    id: cb.getAttribute('data-id'),
                    height: parseFloat(cb.closest('tr').querySelector('td:nth-child(6)').textContent.replace('m', '').replace(',', '.'))
                  };
                });
                sketchup.createCeilingSections(levelsToCreate);
              }

              function createVerticalSections() {
                sketchup.createVerticalSections();
              }

              function createExtraCutX() {
                sketchup.createExtraCutX();
              }

              function createExtraCutY() {
                sketchup.createExtraCutY();
              }
            </script>
          </body>
          </html>
        HTML

        @dialog.set_html(html)

        # Callbacks
        @dialog.add_action_callback('addLevel') do |action_context, name, base_z, height, plan_height|
