    def self.add_level(name, base_z, height, plan_height)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation("#{obter_texto(:botao_criar)} #{name}", true)

      level = {
        id: Time.now.to_i,
        name: name,
        base_z: base_z,
        height: height,
        plan_height: plan_height,
        created_at: Time.now
      }

      @levels << level
      @levels.sort_by! { |l| l[:base_z] }

      model.commit_operation

      update_ui
    end

    def self.save_level(level_id, name, base_z, height, plan_height)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation("#{obter_texto(:botao_salvar)} #{name}", true)

      level = @levels.find { |l| l[:id].to_s == level_id }
      return unless level

      if name != level[:name] && @levels.any? { |l| l[:name].casecmp(name.downcase) == 0 }
        show_alert(obter_texto(:titulo_alerta), obter_texto(:nome_duplicado))
        return
      end

      level[:name] = name unless name.empty?
      level[:base_z] = base_z
      level[:height] = height
      level[:plan_height] = plan_height

      @levels.sort_by! { |l| l[:base_z] }

      model.commit_operation

      update_ui
    end

    def self.edit_level_field(level_id, field, value)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation("#{obter_texto(:editar_pavimento)}", true)

      level = @levels.find { |l| l[:id].to_s == level_id }
      return unless level

      case field
      when 'name'
        level[:name] = value.to_s
      when 'base_z'
        level[:base_z] = value.to_s.gsub(',', '.').to_f
        @levels.sort_by! { |l| l[:base_z] }
      when 'height'
        level[:height] = value.to_s.gsub(',', '.').to_f
      when 'plan_height'
        level[:plan_height] = value.to_s.gsub(',', '.').to_f
      end

      model.commit_operation

      update_ui
    end

    def self.create_sections(levels_data)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation(obter_texto(:secoes_planta), true)

      layers = model.layers
      section_layer = layers.add(obter_texto(:secoes_planta)) unless layers[obter_texto(:secoes_planta)]
      section_layer ||= layers[obter_texto(:secoes_planta)]

      model.entities.grep(Sketchup::SectionPlane) do |e|
        e.erase! if e.layer == section_layer
      end

      created = 0
      levels_data.each do |level_data|
        level = @levels.find { |l| l[:id].to_s == level_data['id'] }
        next unless level

        begin
          z_position = level[:base_z] + level[:plan_height]

          z_position_in_inches = case @current_unit
            when 'metros' then z_position.m
            when 'centimetros' then (z_position * 100).cm
            when 'milimetros' then (z_position * 1000).mm
            when 'polegadas' then z_position.inch
            when 'jardas' then z_position.yd
            when 'pes' then z_position.ft
            else z_position.m
          end

          plane = [0, 0, -1, z_position_in_inches]
          section = model.entities.add_section_plane(plane)
          section.name = "#{level[:name]} - #{obter_texto(:secoes_planta)}"
          section.layer = section_layer
          section.visible = true

          if section.respond_to?(:cutting_plane_visible=)
            section.cutting_plane_visible = true
          end

          created += 1
        rescue => e
          puts "Error creating section for level #{level[:name]}: #{e.message}\n#{e.backtrace.join("\n")}"
          show_alert(obter_texto(:erro), "#{obter_texto(:erro)}: #{e.message}")
        end
      end

      model.commit_operation
    end

    def self.create_ceiling_sections(levels_data)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation(obter_texto(:secoes_forro), true)

      layers = model.layers
      section_layer = layers.add(obter_texto(:secoes_forro)) unless layers[obter_texto(:secoes_forro)]
      section_layer ||= layers[obter_texto(:secoes_forro)]

      model.entities.grep(Sketchup::SectionPlane) do |e|
        e.erase! if e.layer == section_layer
      end

      created = 0
      levels_data.each do |level_data|
        level = @levels.find { |l| l[:id].to_s == level_data['id'] }
        next unless level

        begin
          z_position = level[:base_z] + level[:plan_height]

          z_position_in_inches = case @current_unit
            when 'metros' then z_position.m
            when 'centimetros' then (z_position * 100).cm
            when 'milimetros' then (z_position * 1000).mm
            when 'polegadas' then z_position.inch
            when 'jardas' then z_position.yd
            when 'pes' then z_position.ft
            else z_position.m
          end

          plane = [0, 0, 1, -z_position_in_inches]
          section = model.entities.add_section_plane(plane)
          section.name = "#{level[:name]} - #{obter_texto(:secoes_forro)}"
          section.layer = section_layer
          section.visible = true

          if section.respond_to?(:cutting_plane_visible=)
            section.cutting_plane_visible = true
          end

          created += 1
        rescue => e
          puts "Error creating ceiling section for level #{level[:name]}: #{e.message}\n#{e.backtrace.join("\n")}"
          show_alert(obter_texto(:erro), "#{obter_texto(:erro)}: #{e.message}")
        end
      end

      model.commit_operation
    end

   def self.create_vertical_sections
    model = Sketchup.active_model
    return unless model.valid?

    model.start_operation(obter_texto(:secoes_corte), true)

    # Abordagem HIBRIDA: primeiro tenta o metodo rapido, depois fallback para metodo completo
    bounding_box = Geom::BoundingBox.new

    # 1. Tenta o metodo rapido primeiro (funciona na maioria dos casos)
    quick_bb = model.bounds
    unless quick_bb.empty?
      bounding_box.add(quick_bb)
    else
      # 2. Fallback: metodo manual otimizado para XRefs
      model.entities.each do |entity|
        next unless entity.visible?

        if entity.is_a?(Sketchup::Face)
          entity.vertices.each { |v| bounding_box.add(v.position) }
        elsif entity.is_a?(Sketchup::Group) && entity.visible?
          entity.bounds.each { |point| bounding_box.add(point.transform(entity.transformation)) }
        elsif entity.is_a?(Sketchup::ComponentInstance) && entity.visible?
          # Para componentes e XRefs, usa a bounding box transformada
          entity.bounds.each { |point| bounding_box.add(point.transform(entity.transformation)) }
        end
      end
    end

    if bounding_box.empty?
      UI.messagebox(obter_texto(:sem_geometria))
      model.abort_operation
      return
    end

    min_point = bounding_box.min
    max_point = bounding_box.max

    # Calcula o centro REAL da geometria
    center_x = (min_point.x + max_point.x) / 2.0
    center_y = (min_point.y + max_point.y) / 2.0

    # Offset a partir do centro (em metros)
    offset = @section_offset || 1.0.m

    layers = model.layers
    section_layer = layers.add(obter_texto(:secoes_corte)) unless layers[obter_texto(:secoes_corte)]
    section_layer ||= layers[obter_texto(:secoes_corte)]

    # Remove secoes existentes apenas desta camada
    model.entities.grep(Sketchup::SectionPlane) do |e|
      e.erase! if e.layer == section_layer
    end

    # Cortes posicionados com offset A PARTIR DO CENTRO
    # Secoes no eixo Y (frente/tras) - offset a partir do centro Y
    create_section_plane([0, 1, 0, -(center_y - offset)], "#{obter_texto(:secao)} #{obter_texto(:secao_frente)}", section_layer)
    create_section_plane([0, -1, 0, center_y + offset], "#{obter_texto(:secao)} #{obter_texto(:secao_tras)}", section_layer)

    # Secoes no eixo X (direita/esquerda) - offset a partir do centro X
    create_section_plane([1, 0, 0, -(center_x - offset)], "#{obter_texto(:secao)} #{obter_texto(:secao_direita)}", section_layer)
    create_section_plane([-1, 0, 0, center_x + offset], "#{obter_texto(:secao)} #{obter_texto(:secao_esquerda)}", section_layer)

    model.commit_operation
   end

   def self.create_extra_cut_x
    model = Sketchup.active_model
    return unless model.valid?

    model.start_operation(obter_texto(:corte_extra_x), true)

    # Metodo otimizado para cortes extras
    bounding_box = Geom::BoundingBox.new
    quick_bb = model.bounds

    unless quick_bb.empty?
      bounding_box.add(quick_bb)
    else
      # Fallback manual
      model.entities.grep(Sketchup::ComponentInstance) do |instance|
        next unless instance.visible?
        instance.bounds.each { |point| bounding_box.add(point.transform(instance.transformation)) }
      end
    end

    if bounding_box.empty?
      UI.messagebox(obter_texto(:criar_secoes_primeiro))
      model.abort_operation
      return
    end

    center_x = (bounding_box.min.x + bounding_box.max.x) / 2.0

    layers = model.layers
    section_layer = layers[obter_texto(:secoes_corte)] || layers.add(obter_texto(:secoes_corte))

    # Cria o corte extra exatamente no centro do eixo X
    create_section_plane([0, 1, 0, -center_x], "#{obter_texto(:secao)} #{obter_texto(:corte_extra_x)}", section_layer)

    model.commit_operation
   end

   def self.create_extra_cut_y
    model = Sketchup.active_model
    return unless model.valid?

    model.start_operation(obter_texto(:corte_extra_y), true)

    # Metodo otimizado para cortes extras
    bounding_box = Geom::BoundingBox.new
    quick_bb = model.bounds

    unless quick_bb.empty?
      bounding_box.add(quick_bb)
    else
      # Fallback manual
      model.entities.grep(Sketchup::ComponentInstance) do |instance|
        next unless instance.visible?
        instance.bounds.each { |point| bounding_box.add(point.transform(instance.transformation)) }
      end
    end

    if bounding_box.empty?
      UI.messagebox(obter_texto(:criar_secoes_primeiro))
      model.abort_operation
      return
    end

    center_y = (bounding_box.min.y + bounding_box.max.y) / 2.0

    layers = model.layers
    section_layer = layers[obter_texto(:secoes_corte)] || layers.add(obter_texto(:secoes_corte))

    # Cria o corte extra exatamente no centro do eixo Y
    create_section_plane([1, 0, 0, -center_y], "#{obter_texto(:secao)} #{obter_texto(:corte_extra_y)}", section_layer)

    model.commit_operation
   end

    def self.create_section_plane(plane_equation, name, layer)
      section = Sketchup.active_model.entities.add_section_plane(plane_equation)
      section.name = name
      section.layer = layer
      section.visible = true
      if section.respond_to?(:cutting_plane_visible=)
        section.cutting_plane_visible = true
      end
      section
    end

    def self.delete_levels(level_ids)
      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation(obter_texto(:botao_excluir), true)

      @levels.delete_if { |l| level_ids.include?(l[:id].to_s) }

      update_ui
      model.commit_operation
    end

    def self.load_level(level_id)
      level = @levels.find { |l| l[:id] == level_id.to_i }
      return unless level

      js = <<-JS
        try {
          document.getElementById('level_name').value = #{level[:name].to_json};
          document.getElementById('base_level').value = #{'%.2f' % level[:base_z]}.replace('.', ',');
          document.getElementById('level_height').value = #{'%.2f' % level[:height]}.replace('.', ',');
          document.getElementById('plan_height').value = #{'%.2f' % level[:plan_height]}.replace('.', ',');
        } catch(e) { console.error(e); }
      JS

      @dialog.execute_script(js)
    rescue => e
      puts "Error loading level: #{e.message}\n#{e.backtrace.join("\n")}"
    end

    def self.update_ui
      js = <<-JS
        try {
          const levelsList = document.getElementById('levels_list');
          const levelSelector = document.getElementById('level_selector');
          const unitSelector = document.getElementById('unit_selector');

          levelsList.innerHTML = '';
          levelSelector.innerHTML = '<option value="">#{obter_texto(:selecionar_pavimento)}</option>';

          unitSelector.value = #{@current_unit.to_json};

          #{@levels.sort_by { |l| l[:base_z] }.map do |level|
            pb_z = level[:base_z] + level[:plan_height]

            <<-JS
              var option = document.createElement('option');
              option.value = '#{level[:id]}';
              option.text = #{level[:name].to_json};
              levelSelector.appendChild(option);

              var row = document.createElement('tr');
              row.innerHTML = `
                <td class="checkbox-column"><input type="checkbox" data-id="#{level[:id]}"></td>
                <td class="editable-cell" onclick="editCell(this, '#{level[:id]}', 'name', true)">#{level[:name]}</td>
                <td class="editable-cell" onclick="editCell(this, '#{level[:id]}', 'base_z')">#{'%.2f' % level[:base_z]}m</td>
                <td class="editable-cell" onclick="editCell(this, '#{level[:id]}', 'height')">#{'%.2f' % level[:height]}m</td>
                <td class="editable-cell" onclick="editCell(this, '#{level[:id]}', 'plan_height')">#{'%.2f' % level[:plan_height]}m</td>
                <td>#{'%.2f' % pb_z}m</td>
              `;
              levelsList.appendChild(row);
            JS
          end.join}
        } catch(e) { console.error(e); }
      JS

      @dialog.execute_script(js)
    rescue => e
      puts "Error updating UI: #{e.message}\n#{e.backtrace.join("\n")}"
    end

    def self.load_data_from_file
      path = UI.openpanel(obter_texto(:carregar_dados), "", "JSON Files|*.json||")
      return unless path && File.exist?(path)

      unless File.extname(path).downcase == '.json'
        show_alert(obter_texto(:erro), obter_texto(:arquivo_invalido))
        return
      end

      model = Sketchup.active_model
      return unless model.valid?

      model.start_operation(obter_texto(:carregar_dados), true)

      json_data = File.read(path)
      data = JSON.parse(json_data)

      @levels = data.map do |level|
        {
          id: level['id'] || Time.now.to_i,
          name: level['name'],
          base_z: level['base_z'].to_f,
          height: level['height'].to_f,
          plan_height: level['plan_height'].to_f,
          created_at: level['created_at'] ? Time.parse(level['created_at']) : Time.now
        }
      end

      @levels.sort_by! { |l| l[:base_z] }

      if data.first && data.first['preferences']
        prefs = data.first['preferences']
        @current_unit = prefs['unit'] if prefs['unit']
        @current_theme = prefs['theme'] if prefs['theme']
        @current_language = prefs['language'] if prefs['language']
      end

      model.commit_operation
      update_ui
    rescue => e
      model.abort_operation if model
      show_alert(obter_texto(:erro), "#{obter_texto(:erro)}: #{e.message}")
    end

    def self.save_data_to_file
      return if @levels.empty?

      path = UI.savepanel(obter_texto(:botao_salvar_dados), "", "niveis_pavimentos.json", "JSON Files|*.json||")
      return unless path

      path += ".json" unless path.downcase.end_with?('.json')

      data = @levels.map do |level|
        {
          id: level[:id],
          name: level[:name],
          base_z: level[:base_z],
          height: level[:height],
          plan_height: level[:plan_height],
          created_at: level[:created_at].to_s
        }
      end

      data.first[:preferences] = {
        unit: @current_unit,
        theme: @current_theme,
        language: @current_language.to_s
      }

      File.open(path, 'w') { |f| f.write(JSON.pretty_generate(data)) }

      show_alert(obter_texto(:dados_salvos), path)
    rescue => e
      show_alert(obter_texto(:erro), "#{obter_texto(:erro)}: #{e.message}")
    end

    def self.executar
      criar_interface_niveis
    end

    unless file_loaded?(__FILE__)
      UI.menu('Plugins').add_item(obter_texto(:titulo)) { executar }
      file_loaded(__FILE__)
    end

  end
end

