module ScriptUpComunidade
  module SelecaoPorAngulo

    IDIOMAS = {
      'pt-BR' => {
        :titulo_janela   => "Seleção de Arestas por Ângulo",
        :cabecalho       => "Selecionar Arestas por Ângulo",
        :label_slider    => "Ângulo Máximo (0º a 180º)",
        :botao_atualizar => "Atualizar Seleção Base",
        :erro_selecao    => "Selecione ao menos uma aresta.",
        :sucesso_base    => "Nova seleção base atualizada."
      },
      'en-US' => {
        :titulo_janela   => "Select Edges by Angle",
        :cabecalho       => "Select Edges by Angle",
        :label_slider    => "Maximum Angle (0º to 180º)",
        :botao_atualizar => "Update Base Selection",
        :erro_selecao    => "Please select at least one edge.",
        :sucesso_base    => "New base selection updated."
      },
      'es' => {
        :titulo_janela   => "Selección de Aristas por Ángulo",
        :cabecalho       => "Seleccionar Aristas por Ángulo",
        :label_slider    => "Ángulo Máximo (0º a 180º)",
        :botao_atualizar => "Actualizar Selección Base",
        :erro_selecao    => "Seleccione al menos una arista.",
        :sucesso_base    => "Nueva selección base actualizada."
      }
    }

    def self.obter_texto(chave)
      locale = Sketchup.get_locale
      lang   = IDIOMAS.key?(locale) ? locale : 'en-US'
      IDIOMAS[lang][chave] || IDIOMAS['en-US'][chave] || chave.to_s
    end

    def self.executar
      model = Sketchup.active_model
      selection = model.selection
      $stored_edges = selection.grep(Sketchup::Edge)

      dlg = UI::HtmlDialog.new(
        dialog_title: obter_texto(:titulo_janela),
        scrollable: true,
        resizable: true,
        width: 400,
        height: 300,
        style: UI::HtmlDialog::STYLE_DIALOG
      )

      html = <<-HTML
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <style>
          body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 20px;
          }
          h2 {
            font-size: 18px;
            margin-bottom: 10px;
            color: #323232;
          }
          .form-group {
            margin-bottom: 15px;
          }
          .form-label {
            margin-bottom: 5px;
            font-weight: 600;
          }
          input[type=range] {
            width: 100%;
          }
          .value-display {
            text-align: center;
            font-size: 16px;
            margin-top: 10px;
            font-weight: bold;
          }
          button {
            margin-top: 20px;
            width: 100%;
            padding: 10px;
            background-color: #0078d4;
            color: white;
            border: none;
            border-radius: 4px;
            font-weight: bold;
            cursor: pointer;
          }
          button:hover {
            background-color: #005a9e;
          }
        </style>
      </head>
      <body>
        <h2>#{obter_texto(:cabecalho)}</h2>
        <div class="form-group">
          <label class="form-label" for="angleRange">#{obter_texto(:label_slider)}</label>
          <input type="range" min="0" max="180" value="25" id="angleRange" />
          <div class="value-display" id="angleValue">25°</div>
        </div>
        <button onclick="updateBase()">#{obter_texto(:botao_atualizar)}</button>

        <script>
          const slider = document.getElementById('angleRange');
          const display = document.getElementById('angleValue');

          slider.oninput = function() {
            const value = parseInt(this.value);
            display.innerText = value + '°';
            sketchup.update_angle(value);
          };

          function updateBase() {
            sketchup.update_selection();
          }
        </script>
      </body>
      </html>
      HTML

      dlg.set_html(html)

      dlg.add_action_callback("update_angle") do |dialog, value|
        angle = value.to_f
        max_angle_rad = angle * Math::PI / 180.0
        final_edges = []

        if $stored_edges
          $stored_edges.each { |edge|
            [edge.start, edge.end].each { |start_vertex|
              current_edge = edge
              current_vertex = start_vertex
              chain = [current_edge]

              loop do
                other_vertex = current_edge.other_vertex(current_vertex)
                connected_edges = other_vertex.edges - [current_edge] - chain

                min_angle = nil
                next_edge = nil

                connected_edges.each { |e|
                  vec1 = current_vertex.position.vector_to(other_vertex.position)
                  vec2 = e.start == other_vertex ? e.start.position.vector_to(e.end.position) : e.end.position.vector_to(e.start.position)
                  ang = vec1.angle_between(vec2)

                  if ang <= max_angle_rad && (min_angle.nil? || ang < min_angle)
                    min_angle = ang
                    next_edge = e
                  end
                }

                break unless next_edge
                chain << next_edge
                current_vertex = other_vertex
                current_edge = next_edge
              end

              final_edges.concat(chain)
            }
          }

          model.selection.clear
          model.selection.add(final_edges.uniq)
        end
      end

      dlg.add_action_callback("update_selection") do |dialog, _|
        new_edges = model.selection.grep(Sketchup::Edge)
        if new_edges.empty?
          UI.messagebox(obter_texto(:erro_selecao))
        else
          $stored_edges = new_edges
          UI.messagebox(obter_texto(:sucesso_base))
        end
      end

      dlg.show
    end

  end
end

