module ScriptUpComunidade
  module SuavizarArestasInterativo

    IDIOMAS = {
      'pt-BR' => {
        :erro_selecao    => "Selecione um único grupo ou componente para aplicar o suavizador.",
        :op_suavizar     => "Suavizar Arestas",
        :titulo_janela   => "Suavizar Arestas Interativo",
        :label_angulo    => "Ângulo Máximo para Suavização",
        :btn_fechar      => "Fechar",
        :btn_aplicar     => "Aplicar",
        :status_concluido => "Concluído"
      },
      'en-US' => {
        :erro_selecao    => "Select a single group or component to apply the smoother.",
        :op_suavizar     => "Soften Edges",
        :titulo_janela   => "Interactive Soften Edges",
        :label_angulo    => "Maximum Angle for Softening",
        :btn_fechar      => "Close",
        :btn_aplicar     => "Apply",
        :status_concluido => "Done"
      },
      'es' => {
        :erro_selecao    => "Seleccione un solo grupo o componente para aplicar el suavizador.",
        :op_suavizar     => "Suavizar Aristas",
        :titulo_janela   => "Suavizar Aristas Interactivo",
        :label_angulo    => "Ángulo Máximo para Suavización",
        :btn_fechar      => "Cerrar",
        :btn_aplicar     => "Aplicar",
        :status_concluido => "Concluido"
      }
    }

    def self.obter_texto(chave)
      locale = Sketchup.get_locale
      lang   = IDIOMAS.key?(locale) ? locale : 'en-US'
      IDIOMAS[lang][chave] || IDIOMAS['en-US'][chave] || chave.to_s
    end

    def self.iniciar
      model = Sketchup.active_model
      selection = model.selection

      unless selection.length == 1 && (selection.first.is_a?(Sketchup::Group) || selection.first.is_a?(Sketchup::ComponentInstance))
        UI.messagebox(obter_texto(:erro_selecao))
        return
      end

      @entidade_raiz = selection.first
      @transformacao_raiz = @entidade_raiz.transformation

      mostrar_interface
    end

    def self.aplicar_suavizacao(angulo_graus)
      model = Sketchup.active_model
      view = model.active_view
      model.start_operation(obter_texto(:op_suavizar), true)

      @dialog.execute_script("atualizar_progresso(0)")
      angulo_radianos = angulo_graus.to_f.degrees

      contar_total = contar_arestas(@entidade_raiz)
      @processadas = 0
      @total_arestas = contar_total

      suavizar_entidade(@entidade_raiz, @transformacao_raiz, angulo_radianos)

      @dialog.execute_script("atualizar_progresso(100)")
      model.commit_operation
      view.invalidate
    end

    def self.contar_arestas(entidade)
      total = 0
      if entidade.is_a?(Sketchup::Group) || entidade.is_a?(Sketchup::ComponentInstance)
        definicao = entidade.definition
        definicao.entities.each do |e|
          if e.is_a?(Sketchup::Group) || e.is_a?(Sketchup::ComponentInstance)
            total += contar_arestas(e)
          elsif e.is_a?(Sketchup::Edge) && e.faces.length == 2
            total += 1
          end
        end
      end
      total
    end

    def self.suavizar_entidade(entidade, tr_global, angulo_maximo)
      if entidade.is_a?(Sketchup::Group) || entidade.is_a?(Sketchup::ComponentInstance)
        definicao = entidade.definition
        tr_local = entidade.transformation
        nova_tr = tr_global * tr_local

        definicao.entities.each do |e|
          if e.is_a?(Sketchup::Group) || e.is_a?(Sketchup::ComponentInstance)
            suavizar_entidade(e, nova_tr, angulo_maximo)
          elsif e.is_a?(Sketchup::Edge) && e.faces.length == 2
            suavizar_ou_nao(e, angulo_maximo)
          end
        end
      end
    end

    def self.suavizar_ou_nao(aresta, angulo_maximo)
      faces = aresta.faces
      return unless faces.length == 2

      normal1 = faces[0].normal
      normal2 = faces[1].normal
      return unless normal1 && normal2

      angulo = normal1.angle_between(normal2)

      if angulo <= angulo_maximo
        aresta.soft = true
        aresta.smooth = true
      else
        aresta.soft = false
        aresta.smooth = false
      end

      @processadas += 1
      if @processadas % 100 == 0 || @processadas == @total_arestas
        progresso = ((@processadas.to_f / @total_arestas) * 100).round
        @dialog.execute_script("atualizar_progresso(#{progresso})")
      end
    end

    def self.mostrar_interface
      @dialog = UI::HtmlDialog.new({
        dialog_title: obter_texto(:titulo_janela),
        width: 500,
        height: 260,
        style: UI::HtmlDialog::STYLE_DIALOG
      })

      html = <<-HTML
        <!DOCTYPE html>
        <html>
        <head>
          <meta charset="UTF-8">
          <style>
            body { font-family: "Segoe UI", Tahoma, sans-serif; padding: 20px; margin: 0; background-color: #f9f9f9; color: #333; }
            h5 { margin-bottom: 16px; font-size: 16px; font-weight: 600; }
            .slider-container { position: relative; width: 100%; padding-top: 24px; }
            input[type="range"] { width: 100%; margin: 0; }
            .tooltip { position: absolute; top: 0; transform: translateX(-50%); background: #0053a0; color: white; padding: 4px 10px; border-radius: 6px; font-size: 13px; white-space: nowrap; }
            .progresso-indicador { margin-top: 24px; text-align: center; font-size: 14px; font-weight: bold; color: #0053a0; }
            .button-container { text-align: center; margin-top: 24px; }
            button { min-width: 140px; padding: 8px 20px; font-weight: 600; font-size: 14px; border: none; border-radius: 6px; cursor: pointer; color: white; }
            .btn-primary { background-color: #0053a0; }
            .btn-success { background-color: #2e8540; }
            .btn-primary:hover { background-color: #003d7a; }
            .btn-success:hover { background-color: #256e34; }
          </style>
        </head>
        <body>
          <h5>#{obter_texto(:label_angulo)}</h5>
          <div class="slider-container">
            <div id="tooltip" class="tooltip">85°</div>
            <input id="slider" type="range" min="0" max="180" step="1" value="85" oninput="onSliderChange(this.value)">
          </div>
          <div id="progresso_texto" class="progresso-indicador">0%</div>
          <div class="button-container">
            <button id="actionButton" class="btn-primary" onclick="botaoAcao()">#{obter_texto(:btn_fechar)}</button>
          </div>
          <script>
            const slider = document.getElementById("slider");
            const tooltip = document.getElementById("tooltip");
            const button = document.getElementById("actionButton");
            const txt_fechar = "#{obter_texto(:btn_fechar)}";
            const txt_aplicar = "#{obter_texto(:btn_aplicar)}";
            const txt_concluido = "#{obter_texto(:status_concluido)}";
            let valorAplicado = "85";

            function onSliderChange(valor) {
              tooltip.innerText = valor + "°";
              atualizarTooltip();
              if (valor !== valorAplicado) {
                button.innerText = txt_aplicar;
                button.className = "btn-success";
              } else {
                button.innerText = txt_fechar;
                button.className = "btn-primary";
              }
            }

            function botaoAcao() {
              const valorAtual = slider.value;
              if (button.innerText === txt_aplicar) {
                atualizar_progresso(0);
                sketchup.aplicar_angulo(valorAtual);
                valorAplicado = valorAtual;
                button.innerText = txt_fechar;
                button.className = "btn-primary";
              } else {
                sketchup.fechar_janela();
              }
            }

            function atualizarTooltip() {
              const percent = (slider.value - slider.min) / (slider.max - slider.min);
              const rangeWidth = slider.offsetWidth;
              const pos = percent * (rangeWidth - 16) + 8;
              tooltip.style.left = pos + "px";
            }

            function atualizar_progresso(valor) {
              const texto = document.getElementById("progresso_texto");
              texto.innerText = valor >= 100 ? txt_concluido : valor + "%";
            }

            window.onload = () => {
              atualizarTooltip();
              setTimeout(() => {
                sketchup.aplicar_angulo(slider.value);
              }, 150);
            };

            slider.addEventListener("input", atualizarTooltip);
          </script>
        </body>
        </html>
      HTML

      @dialog.set_html(html)

      @dialog.add_action_callback("aplicar_angulo") do |_, angulo|
        aplicar_suavizacao(angulo.to_f)
      end

      @dialog.add_action_callback("fechar_janela") do |_|
        @dialog.close
      end

      @dialog.show
    end

  end
end

