    class MalhaPreviewTool
      def initialize(model, face, loops2d, umin, umax, vmin, vmax, plane, t_l2w, modulo)
        @model = model
        @face = face
        @loops2d = loops2d
        @umin, @umax = umin, umax
        @vmin, @vmax = vmin, vmax
        @plane = plane
        @t_l2w = t_l2w
        @modulo = modulo
        @eps = 1.0e-6
