      end

      def activate
        @model.start_operation(@modulo.obter_texto(:operacao_nome), true)
        criar_dialogo
        calcular_linhas(50)
      end

      def deactivate(view)
        @dialog.close if @dialog && @dialog.visible?
        @model.abort_operation unless @is_applied
        view.invalidate
      end

      def draw(view)
        return if @draw_points.empty?
        view.drawing_color = "red"
        view.line_width = 2
        view.draw(GL_LINES, @draw_points)
      end
      
      def calcular_linhas(step_val)
        step = step_val.to_f.mm
        return if step <= 0.0

        @draw_points.clear
        
        uc = 0.5 * (@umin + @umax)
        vc = 0.5 * (@vmin + @vmax)
        nx = ((@umax - @umin) * 0.5 / step).floor
        ny = ((@vmax - @vmin) * 0.5 / step).floor

        vx = [uc]
        (1..nx).each { |k| vx << (uc + k*step) << (uc - k*step) }
        vx.select! { |x| x > @umin + @eps && x < @umax - @eps }
        vx = unique_sorted(vx, @eps)

        vy = [vc]
        (1..ny).each { |k| vy << (vc + k*step) << (vc - k*step) }
        vy.select! { |y| y > @vmin + @eps && y < @vmax - @eps }
        vy = unique_sorted(vy, @eps)

        vx.each do |ux|
          ys = crossings_for_x(ux, @loops2d, @eps)
          next if ys.length.odd?
          (0...(ys.length/2)).each do |i|
            y0, y1 = ys[2*i], ys[2*i + 1]
            brk = [y0] + vy.select { |yy| yy > y0 + @eps && yy < y1 - @eps } + [y1]
            brk = unique_sorted(brk, @eps)
            (0...brk.length-1).each do |j|
              adicionar_ponto(ux, brk[j], ux, brk[j+1])
            end
          end
        end

        vy.each do |vyv|
          xs = crossings_for_y(vyv, @loops2d, @eps)
          next if xs.length.odd?
          (0...(xs.length/2)).each do |i|
            x0, x1 = xs[2*i], xs[2*i + 1]
            brk = [x0] + vx.select { |xx| xx > x0 + @eps && xx < x1 - @eps } + [x1]
            brk = unique_sorted(brk, @eps)
            (0...brk.length-1).each do |j|
              adicionar_ponto(brk[j], vyv, brk[j+1], vyv)
            end
          end
        end

        @model.active_view.invalidate
      end

      def adicionar_ponto(x1, y1, x2, y2)
        p1w = (@t_l2w * Geom::Point3d.new(x1, y1, 0)).project_to_plane(@plane)
        p2w = (@t_l2w * Geom::Point3d.new(x2, y2, 0)).project_to_plane(@plane)
        @draw_points << p1w << p2w
      end

      def criar_dialogo
