              clearTimeout(timeout);
              timeout = setTimeout(() => sketchup.update_preview(Number(val)), 10);
            }

            slider.addEventListener('input', (e) => { inputBox.value = e.target.value; update(e.target.value); });
            inputBox.addEventListener('change', (e) => { slider.value = e.target.value; update(e.target.value); });

