          dialog_title: @modulo.obter_texto(:titulo_janela), 
          width: 360, 
          height: 220,
          style: UI::HtmlDialog::STYLE_DIALOG, 
          resizable: false
        })
        @dialog.set_html(html)

        @dialog.add_action_callback("update_preview") { |_, val| calcular_linhas(val) }
        @dialog.add_action_callback("apply_mesh") { |_| aplicar_malha }
        @dialog.add_action_callback("cancel_mesh") { |_| @model.select_tool(nil) }
        
        @dialog.show
      end

      def aplicar_malha
        @is_applied = true
        ents = @face.parent.entities
        created = []
        
        @draw_points.each_slice(2) do |p1, p2|
          e = ents.add_line(p1, p2)
          created << e if e
        end
        
        created.compact.each { |e| e.find_faces if e.valid? && e.faces.empty? }
        created.compact.each do |e|
          if e.valid? && e.faces.length == 2
            e.soft = true
            e.smooth = true
          end
        end
        
        @model.commit_operation
        @dialog.close
        @model.select_tool(nil)
      end

      def unique_sorted(vals, eps)
        vals.sort!
        out = []; last = nil
        vals.each do |v|
          if last.nil? || (v - last).abs > eps
            out << v; last = v
          end
        end
        out
      end

      def crossings_for_x(ux, loops2d, eps)
        ys = []
        loops2d.each do |poly|
          (0...poly.length).each do |i|
            p1 = poly[i]; p2 = poly[(i + 1) % poly.length]
            x1,y1 = p1.x, p1.y; x2,y2 = p2.x, p2.y
            minx, maxx = [x1,x2].min, [x1,x2].max
            next if ux < minx - eps || ux > maxx + eps
            dx = x2 - x1; next if dx.abs < eps
            t = (ux - x1) / dx; next if t <= 0.0 || t > 1.0 + 1e-12
            ys << (y1 + t*(y2 - y1))
          end
        end
        unique_sorted(ys, eps)
      end

      def crossings_for_y(vy, loops2d, eps)
        xs = []
        loops2d.each do |poly|
          (0...poly.length).each do |i|
            p1 = poly[i]; p2 = poly[(i + 1) % poly.length]
            x1,y1 = p1.x, p1.y; x2,y2 = p2.x, p2.y
            miny, maxy = [y1,y2].min, [y1,y2].max
            next if vy < miny - eps || vy > maxy + eps
            dy = y2 - y1; next if dy.abs < eps
            t = (vy - y1) / dy; next if t <= 0.0 || t > 1.0 + 1e-12
            xs << (x1 + t*(x2 - x1))
          end
        end
        unique_sorted(xs, eps)
      end
    end

    def self.executar
      model = Sketchup.active_model
      sel   = model.selection
      unless sel[0].is_a?(Sketchup::Face)
        UI.messagebox(obter_texto(:erro_selecao))
        return
      end
      face = sel[0]
      n = face.normal

      longest = face.edges.max_by { |e| e.length.to_f }
      u = nil
      if longest
        vraw = (longest.end.position - longest.start.position)
        dot  = vraw.dot(n)
        nsc  = Geom::Vector3d.new(n.x * dot, n.y * dot, n.z * dot)
        vproj = vraw - nsc
        u = vproj.length > 1e-6 ? vproj.normalize : nil
      end
      if u.nil? || u.length < 1e-6
        u = n.cross(X_AXIS);
        u = n.cross(Y_AXIS) if u.length < 1e-6
        u.normalize!
      end
      v = n.cross(u).normalize

      plane = [face.vertices.first.position, n]
      bb_center = face.bounds.center
      c = bb_center.project_to_plane(plane)
      t_l2w = Geom::Transformation.axes(c, u, v, n)
      t_w2l = t_l2w.inverse

      loops2d = face.loops.map do |lp|
        pts = lp.vertices.map { |vr| t_w2l * vr.position }
        pts.map! { |p| Geom::Point3d.new(p.x, p.y, 0) }
        pts
      end

      all_pts = loops2d.flatten
      allx = all_pts.map(&:x)
      ally = all_pts.map(&:y)
      umin, umax = allx.min, allx.max
      vmin, vmax = ally.min, ally.max

      model.select_tool(MalhaPreviewTool.new(model, face, loops2d, umin, umax, vmin, vmax, plane, t_l2w, self))
    end

  end
end

