    # ─── Tradução ──────────────────────────────────────────────
    def self.obter_texto(chave)
      locale = Sketchup.get_locale
      lang = IDIOMAS.key?(locale) ? locale : 'en-US'
      IDIOMAS[lang][chave] || IDIOMAS['en-US'][chave] || chave.to_s
    end

    # ─────────────────────────────────────────────────────────────

    OVERLAY_ID = "export_viewport_overlay".freeze

    def self.cleanup_overlay
      model = Sketchup.active_model
      return unless model

      if @ro_observer
        begin
          model.rendering_options.remove_observer(@ro_observer)
        rescue
        end
        @ro_observer = nil
      end

      view = model.active_view
      if defined?(Sketchup::Overlay) && view.respond_to?(:overlays)
        view.overlays.each do |ol|
          if ol.id == OVERLAY_ID
            ol.enabled = false
            break
          end
        end
      end

      @current_ratio = nil
      view.invalidate
    end

    # ─── Letterbox Tool ────────────────────────────────────────

    class LetterboxTool
      def initialize(ratio)
        @ratio = ratio
        @active = true
        @visible = true
      end

      def visible=(v)
        @visible = v
        Sketchup.active_model.active_view.invalidate
      end

      def ratio=(r)
        @ratio = r
        Sketchup.active_model.active_view.invalidate
      end

      def deactivate(view)
        @active = false
        view.invalidate
      end

      def active?
        @active
      end

      def suspend(view)
        view.invalidate
      end

      def resume(view)
        view.invalidate
      end

      def onCancel(reason, view)
        ScriptUpComunidade::ExportViewport.remove_letterbox
        view.invalidate
      end

      def draw(view)
        return unless @active && @visible && @ratio && @ratio > 0

        vw = view.vpwidth.to_f
        vh = view.vpheight.to_f
        return if vw <= 0 || vh <= 0

        viewport_ratio = vw / vh
        target_ratio = @ratio

        overlay_color = Sketchup::Color.new(0, 0, 0, 140)

        if target_ratio > viewport_ratio
          visible_h = vw / target_ratio
          bar_h = (vh - visible_h) / 2.0

          if bar_h > 1
            pts_top = [
              Geom::Point3d.new(0, 0, 0),
              Geom::Point3d.new(vw, 0, 0),
              Geom::Point3d.new(vw, bar_h, 0),
              Geom::Point3d.new(0, bar_h, 0)
            ]
            view.drawing_color = overlay_color
            view.draw2d(GL_QUADS, pts_top)

            pts_bot = [
              Geom::Point3d.new(0, vh - bar_h, 0),
              Geom::Point3d.new(vw, vh - bar_h, 0),
              Geom::Point3d.new(vw, vh, 0),
              Geom::Point3d.new(0, vh, 0)
            ]
            view.drawing_color = overlay_color
            view.draw2d(GL_QUADS, pts_bot)

            border_color = Sketchup::Color.new(255, 255, 255, 80)
            view.line_stipple = ""
            view.line_width = 1
            view.drawing_color = border_color
            view.draw2d(GL_LINES, [
              Geom::Point3d.new(0, bar_h, 0),
              Geom::Point3d.new(vw, bar_h, 0),
              Geom::Point3d.new(0, vh - bar_h, 0),
              Geom::Point3d.new(vw, vh - bar_h, 0)
            ])
          end
        else
          visible_w = vh * target_ratio
          bar_w = (vw - visible_w) / 2.0

          if bar_w > 1
            pts_left = [
              Geom::Point3d.new(0, 0, 0),
              Geom::Point3d.new(bar_w, 0, 0),
              Geom::Point3d.new(bar_w, vh, 0),
              Geom::Point3d.new(0, vh, 0)
            ]
            view.drawing_color = overlay_color
            view.draw2d(GL_QUADS, pts_left)

            pts_right = [
              Geom::Point3d.new(vw - bar_w, 0, 0),
              Geom::Point3d.new(vw, 0, 0),
              Geom::Point3d.new(vw, vh, 0),
              Geom::Point3d.new(vw - bar_w, vh, 0)
            ]
            view.drawing_color = overlay_color
            view.draw2d(GL_QUADS, pts_right)

            border_color = Sketchup::Color.new(255, 255, 255, 80)
            view.line_stipple = ""
            view.line_width = 1
            view.drawing_color = border_color
            view.draw2d(GL_LINES, [
              Geom::Point3d.new(bar_w, 0, 0),
              Geom::Point3d.new(bar_w, vh, 0),
              Geom::Point3d.new(vw - bar_w, 0, 0),
              Geom::Point3d.new(vw - bar_w, vh, 0)
            ])
          end
        end
      end
    end

    @letterbox_tool = nil
    @original_fov = nil

    def self.set_letterbox(width, height)
      return if width <= 0 || height <= 0

      ratio = width.to_f / height.to_f
      model = Sketchup.active_model

      if @letterbox_tool && @letterbox_tool.active?
        @letterbox_tool.ratio = ratio
        @letterbox_tool.visible = true
      else
        @letterbox_tool = LetterboxTool.new(ratio)
        model.select_tool(@letterbox_tool)
      end
    end

    def self.hide_letterbox
      if @letterbox_tool && @letterbox_tool.active?
        @letterbox_tool.visible = false
      end
    end

    def self.remove_letterbox
      if @letterbox_tool
        @letterbox_tool = nil
        Sketchup.active_model.select_tool(nil)
      end
    end

    # ─── FOV Control ───────────────────────────────────────────
    def self.save_original_fov
      camera = Sketchup.active_model.active_view.camera
      @original_fov = camera.perspective? ? camera.fov : nil
    end

    def self.restore_original_fov
      return unless @original_fov
      camera = Sketchup.active_model.active_view.camera
      camera.fov = @original_fov if camera.perspective?
      @original_fov = nil
    end

    def self.set_camera_fov(degrees)
      camera = Sketchup.active_model.active_view.camera
      return unless camera.perspective?
      degrees = [[degrees.to_f, 1.0].max, 120.0].min
      camera.fov = degrees
    end

    def self.current_fov
      camera = Sketchup.active_model.active_view.camera
      camera.perspective? ? camera.fov : nil
    end

    # ─── Export image ──────────────────────────────────────────
    def self.export_image(width, height, antialias)
      model = Sketchup.active_model
      view = model.active_view

      path = UI.savepanel(
        obter_texto(:salvar_imagem),
        "",
        "viewport_export.png"
      )
      return unless path

      path += ".png" unless path.downcase.end_with?(".png", ".jpg", ".jpeg", ".tif", ".tiff", ".bmp")

      had_letterbox = @letterbox_tool && @letterbox_tool.active?
      @letterbox_tool.visible = false if had_letterbox

      keys = {
        :filename    => path,
        :width       => width.to_i,
        :height      => height.to_i,
        :antialias   => antialias,
        :compression => 0.9,
        :transparent => false
      }

      begin
        view.write_image(keys)
        UI.messagebox("#{obter_texto(:exportar_sucesso)}\n\n#{path}")
      rescue => e
        UI.messagebox("#{obter_texto(:erro_exportar)} #{e.message}")
      ensure
        if had_letterbox && @letterbox_tool
          @letterbox_tool.visible = true
        end
      end
    end

