            var ratioText = document.getElementById('ratioText');
            var mpText = document.getElementById('mpText');
            var chips = document.querySelectorAll('.preset-item');
            var btnClose = document.getElementById('btnClose');
            var btnExport = document.getElementById('btnExport');

            var fovSection = document.getElementById('fovSection');
            var fovSlider = document.getElementById('fovSlider');
            var fovValue = document.getElementById('fovValue');
            var fovResetBtn = document.getElementById('fovResetBtn');

            var linked = true;
            var baseRatio = 1920 / 1080;
            var fovIsPerspective = true;
            var fovOriginal = 35.0;

            // ── Helper functions ──
            function gcd(a, b) { return b === 0 ? a : gcd(b, a % b); }

            function initializeFov(fovDegrees, isPerspective) {
              fovIsPerspective = isPerspective;
              if (isPerspective && fovDegrees > 0) {
                fovOriginal = fovDegrees;
                fovSlider.value = fovDegrees;
                fovValue.textContent = fovDegrees.toFixed(1) + '\\u00B0';
              } else {
                fovSection.innerHTML =
                  '<div class="fov-label">' + LANG.campo_visao +
                  '<small>' + LANG.fov_disponivel_perspectiva + '</small></div>' +
                  '<div class="fov-disabled-msg">' + LANG.mudar_perspectiva + '</div>';
              }
            }

            function updateFovSlider(val) {
              fovSlider.value = val;
              fovValue.textContent = val.toFixed(1) + '\\u00B0';
            }

            function updateInfo() {
              var w = parseInt(inputW.value) || 1920;
              var h = parseInt(inputH.value) || 1080;

              var d = gcd(w, h);
              var rw = w / d;
              var rh = h / d;
              if (rw > 50 || rh > 50) {
                var r = w / h;
                if (Math.abs(r - 16/9) < 0.01) { rw = 16; rh = 9; }
                else if (Math.abs(r - 4/3) < 0.01) { rw = 4; rh = 3; }
                else if (Math.abs(r - 21/9) < 0.01) { rw = 21; rh = 9; }
                else if (Math.abs(r - 1) < 0.01) { rw = 1; rh = 1; }
                else { rw = r.toFixed(2); rh = 1; }
              }
              ratioText.textContent = rw + ':' + rh;

              var mp = (w * h) / 1000000;
              mpText.textContent = mp.toFixed(2) + ' MP';

              chips.forEach(function(chip) {
                var cw = parseInt(chip.dataset.w);
                var ch = parseInt(chip.dataset.h);
                chip.classList.toggle('active', cw === w && ch === h);
              });

              if (previewToggle.checked) {
                sketchup.set_letterbox(w + ',' + h);
              }
            }

            // ── Link ratio ──
            linkBtn.addEventListener('click', function() {
              linked = !linked;
              linkBtn.classList.toggle('active', linked);
              if (linked) {
                baseRatio = (parseInt(inputW.value) || 1920) / (parseInt(inputH.value) || 1080);
              }
            });

            // ── Inputs ──
            var debounceTimer = null;

            function debounceUpdate() {
              clearTimeout(debounceTimer);
              debounceTimer = setTimeout(function() {
                updateInfo();
              }, 200);
            }

            inputW.addEventListener('input', function() {
              if (linked) {
                var w = parseInt(inputW.value) || 1920;
                inputH.value = Math.round(w / baseRatio);
              }
              debounceUpdate();
            });

            inputH.addEventListener('input', function() {
              if (linked) {
                var h = parseInt(inputH.value) || 1080;
                inputW.value = Math.round(h * baseRatio);
              }
              debounceUpdate();
            });

            // ── Presets ──
            chips.forEach(function(chip) {
              chip.addEventListener('click', function() {
                var w = parseInt(chip.dataset.w);
                var h = parseInt(chip.dataset.h);
                inputW.value = w;
                inputH.value = h;
                baseRatio = w / h;
                updateInfo();
              });
            });

            // ── FOV slider ──
            fovSlider.addEventListener('input', function() {
              var val = parseFloat(fovSlider.value);
              fovValue.textContent = val.toFixed(1) + '\\u00B0';
              sketchup.set_fov(val.toString());
            });

            fovResetBtn.addEventListener('click', function() {
              sketchup.reset_fov();
            });

            // ── Preview toggle ──
            previewToggle.addEventListener('change', function() {
              if (previewToggle.checked) {
                updateInfo();
              } else {
                sketchup.hide_letterbox();
              }
            });

            // ── Buttons ──
            btnClose.addEventListener('click', function() {
              sketchup.close_dialog();
            });

            btnExport.addEventListener('click', function() {
              var w = parseInt(inputW.value) || 1920;
              var h = parseInt(inputH.value) || 1080;
              var aa = antialiasToggle.checked ? 1 : 0;
              sketchup.export_image(w + ',' + h + ',' + aa);
            });

            // Initialize
            updateInfo();

            // Request initial FOV from SketchUp
            setTimeout(function() {
              sketchup.get_initial_fov();
            }, 100);
          </script>

        </body>
        </html>
      HTML
    end

    # ─── Show dialog ───────────────────────────────────────────
    def self.show_dialog
      cleanup_overlay
      save_original_fov

      dlg = UI::HtmlDialog.new(
        {
          :dialog_title    => obter_texto(:titulo_dialogo),
          :preferences_key => "ExportViewportDialog",
          :width           => 380,
          :height          => 820,
          :resizable       => false,
          :style           => UI::HtmlDialog::STYLE_DIALOG
        }
      )

      # ── Callbacks ──
      dlg.add_action_callback("set_letterbox") do |_ctx, params|
        parts = params.split(",")
        w = parts[0].to_f
        h = parts[1].to_f
        set_letterbox(w, h) if w > 0 && h > 0
      end

      dlg.add_action_callback("remove_letterbox") do |_ctx, _params|
        remove_letterbox
      end

      dlg.add_action_callback("hide_letterbox") do |_ctx, _params|
        hide_letterbox
      end

      dlg.add_action_callback("set_fov") do |_ctx, params|
        degrees = params.to_f
        set_camera_fov(degrees)
      end

      dlg.add_action_callback("reset_fov") do |_ctx, _params|
        if @original_fov
          camera = Sketchup.active_model.active_view.camera
          camera.fov = @original_fov if camera.perspective?
          dlg.execute_script("updateFovSlider(#{@original_fov.round(1)})")
        end
      end

      dlg.add_action_callback("get_initial_fov") do |_ctx, _params|
        camera = Sketchup.active_model.active_view.camera
        if camera.perspective?
          fov_val = camera.fov.round(1)
          dlg.execute_script("initializeFov(#{fov_val}, true)")
        else
          dlg.execute_script("initializeFov(0, false)")
        end
      end

      dlg.add_action_callback("export_image") do |_ctx, params|
        parts = params.split(",")
        w = parts[0].to_i
        h = parts[1].to_i
        aa = parts[2].to_i == 1
        export_image(w, h, aa)
      end

      dlg.add_action_callback("close_dialog") do |_ctx, _params|
        remove_letterbox
        restore_original_fov
        dlg.close
      end

      dlg.set_on_closed {
        remove_letterbox
        restore_original_fov
      }

      dlg.set_html(html_content)
      dlg.show
      @dialog = dlg
    end

    # ─── Entry point ───────────────────────────────────────────
    def self.executar
      show_dialog
    end
  end
end

