# ============================================================
# Cronômetro flutuante ultra compacto – SketchUp
# ============================================================

Sketchup.active_model.start_operation("Cronômetro", true)

if defined?(@cronometro_dialog)
  @cronometro_dialog.close
end

begin
  def cronometro_auto_file
    model_path = Sketchup.active_model.path
    if model_path.empty?
      File.join(ENV['TEMP'], "cronometro_temp.txt")
    else
      File.join(File.dirname(model_path), "#{File.basename(model_path, '.*')}_tempo.txt")
    end
  end

  @cronometro_start = Time.now
  @cronometro_paused = 0
  @cronometro_is_paused = false
  @last_activity_time = Time.now
  @last_camera_state = nil
  @cronometro_check_timer = nil
  @cronometro_save_timer = nil
  @cronometro_initial_load = false

  def update_elapsed_time
    if @cronometro_start && !@cronometro_is_paused
      elapsed = Time.now - @cronometro_start
      @cronometro_paused += elapsed
      @cronometro_start = Time.now
      return elapsed
    end
    0
  end

  def cronometro_format_time(seconds)
    t = seconds.to_i
    h = t/3600; m=(t%3600)/60; s=t%60
    format("%02d:%02d:%02d", h, m, s)
  end

  def cronometro_current_time
    if @cronometro_start && !@cronometro_is_paused
      Time.now - @cronometro_start + @cronometro_paused
    else
      @cronometro_paused
    end
  end

  def cronometro_auto_save
    was_running = update_elapsed_time>0
    current_time=@cronometro_paused
    return if current_time<=0
    File.write(cronometro_auto_file, cronometro_format_time(current_time))
    if was_running
      @cronometro_start=Time.now
      @cronometro_is_paused=false
    end
  end

  def setup_auto_save
    @cronometro_save_timer = UI.start_timer(30,true){ cronometro_auto_save }
  end

  def cronometro_load_time
    return if @cronometro_initial_load
    @cronometro_initial_load=true
    file_path=cronometro_auto_file
    if File.exist?(file_path)
      content = File.read(file_path).strip.gsub("\r","").gsub("\n","")
      if content =~ /\A\d{2}:\d{2}:\d{2}\z/
        h,m,s=content.split(':').map(&:to_i)
        @cronometro_paused=h*3600+m*60+s
      end
    end
  end

  def detect_camera_activity
    view=Sketchup.active_model.active_view
    cam=view.camera
    state=[cam.eye.to_a,cam.target.to_a,cam.up.to_a].flatten
    if @last_camera_state != state
      @last_camera_state = state
      @last_activity_time = Time.now
      if @cronometro_is_paused
        @cronometro_start = Time.now - @cronometro_paused
        @cronometro_is_paused=false
        @cronometro_paused=0
      end
    end
    if !@cronometro_is_paused && (Time.now - @last_activity_time)>=15
      update_elapsed_time
      @cronometro_is_paused=true
    end
  end

  html=<<-HTML
  <!DOCTYPE html>
  <html>
  <head>
    <meta http-equiv="X-UA-Compatible" content="IE=edge">
    <style>
      html, body{margin:0;padding:0;background:transparent;}
      #bar{
        display:flex; align-items:center; background: rgba(30,30,30,0.9);
        border-radius:6px; padding:2px; cursor:move; box-shadow:0 2px 5px rgba(0,0,0,0.4);
      }
      #display{color:white; font-weight:bold; font-size:12px; margin:0 3px; width:70px; text-align:center;}
      button{
        border:none; margin:0 2px; width:24px; height:24px; border-radius:4px;
        cursor:pointer; display:flex; align-items:center; justify-content:center; padding:0;
      }
      #start{background:#4CAF50;}
      #pause{background:#2196F3;}
      #reset{background:#f44336;}
      #save{background:#FFC107;}
      #import{background:#9C27B0;}
      button svg{width:12px; height:12px; fill:white;}
    </style>
    <script>
      let bar, offsetX, offsetY, dragging=false;
      function initDrag(){
        bar=document.getElementById('bar');
        bar.onmousedown=function(e){dragging=true; offsetX=e.clientX-bar.offsetLeft; offsetY=e.clientY-bar.offsetTop;};
        window.onmouseup=function(){dragging=false;};
        window.onmousemove=function(e){if(dragging){bar.style.left=(e.clientX-offsetX)+'px';bar.style.top=(e.clientY-offsetY)+'px';}};
      }
      function updateDisplay(){window.location='skp:getTime@';setTimeout(updateDisplay,500);}
      function setDisplay(v){document.getElementById('display').innerText=v;}
      window.onload=function(){initDrag();updateDisplay();};
    </script>
  </head>
  <body>
    <div id="bar">
      <div id="display">00:00:00</div>
      <button id="start" onclick="window.location='skp:startTimer@'">&#9658;</button>
      <button id="pause" onclick="window.location='skp:pauseTimer@'">&#10074;&#10074;</button>
      <button id="reset" onclick="window.location='skp:resetTimer@'">&#8634;</button>
      <button id="save" onclick="window.location='skp:saveTime@'">
        <svg viewBox="0 0 24 24"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2zM12 17a3 3 0 1 0 0-6 3 3 0 0 0 0 6z"/></svg>
      </button>
      <button id="import" onclick="window.location='skp:importTime@'">
        <svg viewBox="0 0 24 24"><path d="M5 20h14v-2H5v2zm7-18L5.33 9h3.34v4h4V9h3.34L12 2z"/></svg>
      </button>
    </div>
  </body>
  </html>
  HTML

  # Título mínimo da janela: só "Cronômetro"
  @cronometro_dialog = UI::WebDialog.new("Cronômetro", false, "CronometroCompacto", 230, 32, 150, 150)
  @cronometro_dialog.set_html(html)

  # Callbacks
  @cronometro_dialog.add_action_callback("getTime"){|d,_| d.execute_script("setDisplay('#{cronometro_format_time(cronometro_current_time)}');")}
  @cronometro_dialog.add_action_callback("startTimer"){|_,_| if @cronometro_is_paused; @cronometro_start=Time.now-@cronometro_paused; @cronometro_is_paused=false; @cronometro_paused=0; end}
  @cronometro_dialog.add_action_callback("pauseTimer"){|_,_| update_elapsed_time; @cronometro_is_paused=true}
  @cronometro_dialog.add_action_callback("resetTimer"){|_,_| @cronometro_start=nil; @cronometro_paused=0; @cronometro_is_paused=true}
  @cronometro_dialog.add_action_callback("saveTime"){|_,_| cronometro_auto_save; UI.messagebox("Tempo salvo!")}
  @cronometro_dialog.add_action_callback("importTime") do |_,_|
    path=UI.openpanel("Importar Tempo","","*.txt")
    if path && File.exist?(path)
      content=File.read(path).strip.gsub("\r","").gsub("\n","")
      if content=~/\A\d{2}:\d{2}:\d{2}\z/
        h,m,s=content.split(':').map(&:to_i)
        @cronometro_paused=h*3600+m*60+s
        UI.messagebox("Tempo carregado: #{content}")
      else
        UI.messagebox("Formato inválido! Use 00:00:00")
      end
    end
  end

  @cronometro_check_timer=UI.start_timer(1.0,true){ detect_camera_activity }
  setup_auto_save
  cronometro_load_time
  @cronometro_dialog.show

rescue => e
  puts "Erro: #{e.message}"
end

