        :html_btn_aplicar      => "Aplicar",
        :html_btn_cancelar     => "Cancelar",
        :html_btn_fechar       => "Cerrar",
        :html_iniciando        => "Iniciando..."
      }
    }

    def self.obter_texto(chave)
      locale = Sketchup.get_locale
      lang   = IDIOMAS.key?(locale) ? locale : 'en-US'
      IDIOMAS[lang][chave] || IDIOMAS['en-US'][chave] || chave.to_s
    end

    # ========================================================
    # FERRAMENTA DE PICK
    # ========================================================
    class PickTool

      def activate
        @ip = Sketchup::InputPoint.new
        @hover_mat = nil
        Sketchup.status_text = ScriptUpComunidade::SeamlessTexture.obter_texto(:status_clique)
      end

      def deactivate(view)
        view.invalidate
        ScriptUpComunidade::SeamlessTexture.close_dialog
      end

      def onMouseMove(_flags, x, y, view)
        mat = find_material(view, x, y)
        if mat != @hover_mat
          @hover_mat = mat
          if mat
            Sketchup.status_text = "#{ScriptUpComunidade::SeamlessTexture.obter_texto(:status_prefix)}#{mat.display_name}#{ScriptUpComunidade::SeamlessTexture.obter_texto(:status_suffix)}"
          else
            Sketchup.status_text = ScriptUpComunidade::SeamlessTexture.obter_texto(:status_clique)
          end
        end
      end

      def onLButtonDown(_flags, x, y, view)
        mat = find_material(view, x, y)
        if mat
          ScriptUpComunidade::SeamlessTexture.open_dialog(mat)
        else
          UI.messagebox(ScriptUpComunidade::SeamlessTexture.obter_texto(:erro_nenhuma_textura))
        end
      end

      def getExtents
        Sketchup.active_model.bounds
      end

      private

      # Busca material com textura: face → sobe na hierarquia
      def find_material(view, x, y)
        ph = view.pick_helper
        ph.do_pick(x, y)

        # path_at(0) retorna o caminho completo até a entidade
        # mais profunda, mesmo dentro de grupos/componentes
        path = ph.path_at(0) rescue nil
        return nil unless path.is_a?(Array) && !path.empty?

        leaf = path.last

        # 1. Se o leaf é uma face, checar material dela
        if leaf.is_a?(Sketchup::Face)
          [leaf.material, leaf.back_material].each do |m|
            return m if m && m.texture
          end
        end

        # 2. Subir pela hierarquia buscando textura
        #    (do mais profundo ao mais externo)
        path.reverse_each do |ent|
          next if ent == leaf
          next unless ent.respond_to?(:material)
          m = ent.material
          return m if m && m.texture
        end

        nil
      end
    end

    # ========================================================
    # ESTADO DO MÓDULO
    # ========================================================
    @dialog = nil
    @processing = false

    def self.close_dialog
      return unless @dialog
      @dialog.close rescue nil
      @dialog = nil
    end

    # ========================================================
    # ABRIR DIALOG
    # ========================================================
    def self.open_dialog(mat)
      close_dialog if @dialog

      texture = mat.texture
      tw = texture.width
      th = texture.height

      temp_dir = File.join(Dir.tmpdir, 'su_seamless')
      Dir.mkdir(temp_dir) unless Dir.exist?(temp_dir)
      orig_path = File.join(temp_dir, "original.png")
      texture.write(orig_path)

      rep = Sketchup::ImageRep.new(orig_path)
      img_w = rep.width
      img_h = rep.height

      # File URL instead of base64 — avoids encoding overhead and huge HTML string
      url_path = orig_path.gsub('\\', '/')
      img_src = url_path.start_with?('/') ? "file://#{url_path}" : "file:///#{url_path}"

      html = build_html(img_w, img_h, mat.display_name, img_src)

      @dialog = UI::HtmlDialog.new(
        dialog_title: obter_texto(:titulo_dialogo),
        width: 470,
        height: 730,
        resizable: false,
        style: UI::HtmlDialog::STYLE_DIALOG
      )

      @dialog.add_action_callback("apply_result") do |_ctx, ext, b64_data|
        next if @processing
        @processing = true

        UI.start_timer(0.05) do
          begin
            safe_name = mat.display_name.gsub(/[^a-zA-Z0-9_\-]/, '_')
            ext = ext.to_s
            ext = 'png' unless ext == 'jpg'
            out_path = File.join(temp_dir, "seamless_#{safe_name}.#{ext}")

            img_data = b64_data.unpack1('m')
            File.binwrite(out_path, img_data)

            model = Sketchup.active_model
            model.start_operation(obter_texto(:titulo_dialogo), true)
            begin
              mat.texture = out_path
              mat.texture.size = [tw, th]
              model.commit_operation
            rescue => e
              model.abort_operation
              puts "Erro: #{e.message}"
            end

            @processing = false
            @dialog.execute_script("showDone()") rescue nil
            puts "Seamless aplicado: #{mat.display_name} (#{img_w}x#{img_h})"
            puts "Salvo em: #{out_path}"
          rescue => e
            @processing = false
            puts "Erro ao aplicar resultado: #{e.message}"
          end
        end
      end

      @dialog.add_action_callback("cancel") do |_ctx|
        close_dialog unless @processing
      end

      @dialog.set_html(html)
      @dialog.center
      @dialog.show
    end

    # ========================================================
    # HTML DA INTERFACE
    # ========================================================
    def self.build_html(img_w, img_h, mat_name, img_src)
      <<~HTML
      <!DOCTYPE html>
      <html>
      <head>
      <meta charset="utf-8">
      <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body {
          background-color: #f3f3f3; color: #333333;
          font-family: Arial, sans-serif;
          font-size: 14px;
          display: flex; flex-direction: column; align-items: center;
          padding: 20px; gap: 10px;
          user-select: none;
        }
        h3 { font-size: 18px; font-weight: normal; color: #00567e; }
        .info { font-size: 12px; color: #666666; }

        .canvas-wrap {
          border: 1px solid #cccccc; border-radius: 4px;
          overflow: hidden; background: #ffffff;
        }
        canvas { display: block; }

        .legend {
          display: flex; gap: 10px; font-size: 12px; color: #666666;
        }
        .legend-item { display: flex; align-items: center; gap: 5px; }
        .swatch {
          width: 12px; height: 12px; border-radius: 4px;
          border: 1px solid #cccccc;
        }
        .swatch-blend { background: rgba(243, 179, 89, 0.7); }
        .swatch-keep  { background: rgba(211, 243, 211, 0.9); }

        .controls {
          width: 100%; max-width: 420px; display: flex; flex-direction: column; gap: 10px;
        }
        .control-group { display: flex; flex-direction: column; gap: 4px; }
        .slider-row { display: flex; align-items: center; gap: 10px; }
        .slider-label { font-size: 14px; color: #00567e; min-width: 58px; }
        .slider-val { font-size: 14px; font-weight: 600; min-width: 28px; text-align: center; }
        .val-zona { color: #f3b359; }
        .val-dureza { color: #00567e; }

        input[type=range] {
          flex: 1; height: 6px; -webkit-appearance: none;
          background: #eeeeee; border-radius: 4px; outline: none;
          border: 1px solid #cccccc;
        }
        input[type=range]::-webkit-slider-thumb {
          -webkit-appearance: none; width: 16px; height: 16px;
          border-radius: 50%; cursor: pointer; border: 2px solid #ffffff;
        }
        #sliderZona::-webkit-slider-thumb { background: #f3b359; }
        #sliderDureza::-webkit-slider-thumb { background: #00567e; }

        .slider-hints {
          display: flex; justify-content: space-between; font-size: 12px; color: #999999; padding: 0 70px 0 2px;
        }

        .buttons { display: flex; gap: 10px; margin-top: 5px; }
        .btn {
          padding: 10px 20px; border: none; border-radius: 4px;
          font-size: 14px; cursor: pointer;
          transition: background-color 0.15s;
        }
        .btn-apply { background-color: #00567e; color: #ffffff; }
        .btn-apply:hover { background-color: #004d70; }
        .btn-cancel { background-color: #9e9e9e; color: #ffffff; }
        .btn-cancel:hover { background-color: #7d7d7d; }
        .btn-close { background-color: #f3b359; color: #ffffff; }
        .btn-close:hover { background-color: #e3a752; }

        /* Progresso */
        #progressSection {
          display: none; width: 100%; max-width: 420px;
          flex-direction: column; align-items: center; gap: 10px;
        }
        .progress-bar-bg {
          width: 100%; height: 22px; background: #eeeeee;
          border-radius: 4px; overflow: hidden;
          border: 1px solid #cccccc;
        }
        .progress-bar-fill {
          height: 100%; width: 0%; border-radius: 4px;
          background: linear-gradient(90deg, #00567e, #f3b359);
          transition: width 0.2s ease;
        }
        .progress-label {
          font-size: 12px; color: #666666; text-align: center;
        }
        #doneButtons { display: none; }
      </style>
      </head>
      <body>

      <h3>#{obter_texto(:titulo_dialogo)}</h3>
      <div class="info">#{img_w} × #{img_h} px — #{mat_name}</div>

      <div class="canvas-wrap">
        <canvas id="cv"></canvas>
      </div>

      <div class="legend" id="legend">
        <div class="legend-item">
          <div class="swatch swatch-blend"></div><span>#{obter_texto(:html_zona_blend)}</span>
        </div>
        <div class="legend-item">
          <div class="swatch swatch-keep"></div><span>#{obter_texto(:html_preservado)}</span>
        </div>
      </div>

      <div class="controls" id="controlsSection">
        <div class="control-group">
          <div class="slider-row">
            <span class="slider-label">#{obter_texto(:html_zona)}</span>
            <input type="range" id="sliderZona" min="1" max="20" value="5" step="1">
            <span class="slider-val val-zona" id="valZona">5</span>
          </div>
          <div class="slider-hints">
            <span>#{obter_texto(:html_mais_blend)}</span><span>#{obter_texto(:html_mais_original)}</span>
          </div>
        </div>
        <div class="control-group">
          <div class="slider-row">
            <span class="slider-label">#{obter_texto(:html_dureza)}</span>
            <input type="range" id="sliderDureza" min="1" max="10" value="5" step="1">
            <span class="slider-val val-dureza" id="valDureza">5</span>
          </div>
          <div class="slider-hints">
            <span>#{obter_texto(:html_suave)}</span><span>#{obter_texto(:html_abrupto)}</span>
          </div>
        </div>
      </div>

      <div class="buttons" id="mainButtons">
        <button class="btn btn-apply" onclick="aplicar()">#{obter_texto(:html_btn_aplicar)}</button>
        <button class="btn btn-cancel" onclick="cancelar()">#{obter_texto(:html_btn_cancelar)}</button>
      </div>

      <div id="progressSection">
        <div class="progress-bar-bg">
          <div class="progress-bar-fill" id="progressFill"></div>
        </div>
        <div class="progress-label" id="progressLabel">#{obter_texto(:html_iniciando)}</div>
      </div>

      <div class="buttons" id="doneButtons">
        <button class="btn btn-close" onclick="cancelar()">#{obter_texto(:html_btn_fechar)}</button>
      </div>

      <script>
        const IMG_W = #{img_w};
        const IMG_H = #{img_h};
        const IMG_SRC = '#{img_src}';
        const TEXTS = {
          horizontal: '#{obter_texto(:progresso_horizontal)}',
          vertical:   '#{obter_texto(:progresso_vertical)}',
          saving:     '#{obter_texto(:progresso_salvando)}',
          done:       '#{obter_texto(:progresso_concluido)}',
          starting:   '#{obter_texto(:html_iniciando)}'
        };

        const cv  = document.getElementById('cv');
        const ctx = cv.getContext('2d');
        const sliderZ = document.getElementById('sliderZona');
        const sliderD = document.getElementById('sliderDureza');
        const valZ = document.getElementById('valZona');
        const valD = document.getElementById('valDureza');

        const img = new Image();
        img.onload = () => { render(); };
        img.src = IMG_SRC;

        sliderZ.addEventListener('input', () => { valZ.textContent = sliderZ.value; render(); });
        sliderD.addEventListener('input', () => { valD.textContent = sliderD.value; render(); });

        function calcWeight(sinSq, zonaExp, durezaK) {
          let w = Math.pow(sinSq, zonaExp);
          if (durezaK !== 1.0) w = Math.pow(w, durezaK);
          return w;
        }

        function render() {
          const zona   = parseInt(sliderZ.value);
          const dureza = parseInt(sliderD.value);
          const zonaExp = 0.5 + (zona - 1) * 0.553;
          const durezaK = Math.exp((dureza - 5) * 0.32);

          const maxTile = 200;
          const scale = Math.min(maxTile / IMG_W, maxTile / IMG_H);
          const tW = Math.round(IMG_W * scale);
          const tH = Math.round(IMG_H * scale);

          cv.width  = tW * 2;
          cv.height = tH * 2;

          for (let ty = 0; ty < 2; ty++)
            for (let tx = 0; tx < 2; tx++)
              ctx.drawImage(img, tx * tW, ty * tH, tW, tH);

          const sinSqX = new Float64Array(tW);
          for (let x = 0; x < tW; x++) { const s = Math.sin(Math.PI * x / tW); sinSqX[x] = s * s; }
          const sinSqY = new Float64Array(tH);
          for (let y = 0; y < tH; y++) { const s = Math.sin(Math.PI * y / tH); sinSqY[y] = s * s; }

          const overlay = ctx.createImageData(tW, tH);
          const od = overlay.data;
          for (let y = 0; y < tH; y++) {
            const wy = calcWeight(sinSqY[y], zonaExp, durezaK);
            for (let x = 0; x < tW; x++) {
              const wx = calcWeight(sinSqX[x], zonaExp, durezaK);
              const keep = wx * wy;
              const blend = 1.0 - keep;

              const idx = (y * tW + x) * 4;
              od[idx]     = Math.round(243 * blend + 211 * keep);
              od[idx + 1] = Math.round(179 * blend + 243 * keep);
              od[idx + 2] = Math.round(89 * blend + 211 * keep);
              od[idx + 3] = Math.round(blend * 140 + keep * 30);
            }
          }

          const tmpCv = document.createElement('canvas');
          tmpCv.width = tW; tmpCv.height = tH;
          tmpCv.getContext('2d').putImageData(overlay, 0, 0);
          for (let ty = 0; ty < 2; ty++)
            for (let tx = 0; tx < 2; tx++)
              ctx.drawImage(tmpCv, tx * tW, ty * tH);

          ctx.strokeStyle = 'rgba(0,86,126,0.4)';
          ctx.lineWidth = 1;
          ctx.setLineDash([4, 4]);
          ctx.beginPath();
          ctx.moveTo(tW, 0); ctx.lineTo(tW, tH * 2);
          ctx.moveTo(0, tH); ctx.lineTo(tW * 2, tH);
          ctx.stroke();
          ctx.setLineDash([]);
        }

        // =============================================
        // PROCESSAMENTO SEAMLESS EM JS (V8 JIT-compiled)
        // =============================================
        function aplicar() {
          showProgress();
          setProgress(2, TEXTS.starting);
          setTimeout(function() { processSeamless(); }, 50);
        }

        function processSeamless() {
          const t0 = performance.now();
          const zona   = parseInt(sliderZ.value);
          const dureza = parseInt(sliderD.value);
          const w = IMG_W, h = IMG_H;

          // Extrair pixels da imagem original em resolução total
          const offCv = document.createElement('canvas');
          offCv.width = w; offCv.height = h;
          const offCtx = offCv.getContext('2d');
          offCtx.drawImage(img, 0, 0);
          const src = offCtx.getImageData(0, 0, w, h).data;

          // Pré-computar pesos
          const zonaExp = 0.5 + (zona - 1) * 0.553;
          const durezaK = Math.exp((dureza - 5) * 0.32);
          const pi = Math.PI;

          const wxArr = new Float64Array(w);
          for (let x = 0; x < w; x++) {
            const s = Math.sin(pi * x / w);
            let v = Math.pow(s * s, zonaExp);
            if (durezaK !== 1.0) v = Math.pow(v, durezaK);
            wxArr[x] = v;
          }
          const wyArr = new Float64Array(h);
          for (let y = 0; y < h; y++) {
            const s = Math.sin(pi * y / h);
            let v = Math.pow(s * s, zonaExp);
            if (durezaK !== 1.0) v = Math.pow(v, durezaK);
            wyArr[y] = v;
          }

          const hw = w >> 1, hh = h >> 1;
          const p1 = new Uint8ClampedArray(w * h * 4);
          const result = new Uint8ClampedArray(w * h * 4);
          let row = 0;

          // Passada 1: horizontal (chunked para manter UI responsiva)
          function pass1Chunk() {
            const deadline = performance.now() + 40;
            while (row < h && performance.now() < deadline) {
              const rowOff = row * w;
              for (let x = 0; x < w; x++) {
                const wt = wxArr[x], inv = 1.0 - wt;
                const idx  = (rowOff + x) << 2;
                const oidx = (rowOff + ((x + hw) % w)) << 2;
                p1[idx]     = src[idx]     * wt + src[oidx]     * inv;
                p1[idx + 1] = src[idx + 1] * wt + src[oidx + 1] * inv;
                p1[idx + 2] = src[idx + 2] * wt + src[oidx + 2] * inv;
                p1[idx + 3] = src[idx + 3] * wt + src[oidx + 3] * inv;
              }
              row++;
            }
            const pct = Math.round(row / h * 45);
            setProgress(pct, TEXTS.horizontal + ' ' + pct + '%');
            if (row < h) {
              setTimeout(pass1Chunk, 0);
            } else {
              row = 0;
              setTimeout(pass2Chunk, 0);
            }
          }

          // Passada 2: vertical (chunked)
          function pass2Chunk() {
            const deadline = performance.now() + 40;
            while (row < h && performance.now() < deadline) {
              const wt = wyArr[row], inv = 1.0 - wt;
              const rowOff = row * w;
              const oRowOff = ((row + hh) % h) * w;
              for (let x = 0; x < w; x++) {
                const idx  = (rowOff + x) << 2;
                const oidx = (oRowOff + x) << 2;
                result[idx]     = p1[idx]     * wt + p1[oidx]     * inv;
                result[idx + 1] = p1[idx + 1] * wt + p1[oidx + 1] * inv;
                result[idx + 2] = p1[idx + 2] * wt + p1[oidx + 2] * inv;
                result[idx + 3] = p1[idx + 3] * wt + p1[oidx + 3] * inv;
              }
              row++;
            }
            const pct = 45 + Math.round(row / h * 45);
            setProgress(pct, TEXTS.vertical + ' ' + pct + '%');
            if (row < h) {
              setTimeout(pass2Chunk, 0);
            } else {
              finalize();
            }
          }

          // Exportar resultado e enviar para Ruby
          function finalize() {
            setProgress(90, TEXTS.saving);
            const imgData = new ImageData(result, w, h);
            offCtx.putImageData(imgData, 0, 0);

            // Verificar se precisa de canal alfa
            let needsAlpha = false;
            for (let i = 3, len = result.length; i < len; i += 4) {
              if (result[i] < 255) { needsAlpha = true; break; }
            }

            // JPEG: encoding ~50x mais rápido, arquivo ~10x menor que PNG
            // PNG: usado apenas quando a textura tem transparência
            const fmt = needsAlpha ? 'image/png' : 'image/jpeg';
            const ext = needsAlpha ? 'png' : 'jpg';

            offCv.toBlob(function(blob) {
              setProgress(93, TEXTS.saving);
              const reader = new FileReader();
              reader.onload = function() {
                const b64 = reader.result.split(',')[1];
                const totalElapsed = ((performance.now() - t0) / 1000).toFixed(1);
                setProgress(98, TEXTS.done + ' ' + totalElapsed + 's!');
                sketchup.apply_result(ext, b64);
              };
              reader.readAsDataURL(blob);
            }, fmt, fmt === 'image/jpeg' ? 0.97 : undefined);
          }

          pass1Chunk();
        }

        function cancelar() {
          window.location = 'skp:cancel@';
        }

        // --- Progresso ---
        function showProgress() {
          document.getElementById('controlsSection').style.display = 'none';
          document.getElementById('mainButtons').style.display = 'none';
          document.getElementById('legend').style.display = 'none';
          document.getElementById('progressSection').style.display = 'flex';
        }
        function setProgress(pct, label) {
          document.getElementById('progressFill').style.width = pct + '%';
          document.getElementById('progressLabel').textContent = label;
        }
        function showDone() {
          document.getElementById('progressSection').style.display = 'none';
          document.getElementById('doneButtons').style.display = 'flex';
        }
      </script>
      </body>
      </html>
      HTML
    end

    # ========================================================
    # INICIAR
    # ========================================================
    def self.executar
      Sketchup.active_model.select_tool(PickTool.new)
    end

  end
end

ScriptUpComunidade::SeamlessTexture.executar
